-- ─────────────────────────────────────────────────────────────────────────────
-- Import grile: Protetica
-- ─────────────────────────────────────────────────────────────────────────────
-- Generated from grile_protetica_final.xlsx
-- Total questions: 2444
-- Total options:   12220
--
-- Aborts if chapter "Protetica" already exists.
--
-- Usage:
--   psql "<DATABASE_PUBLIC_URL>" -f scripts/sql/05-import-protetica.sql
-- ─────────────────────────────────────────────────────────────────────────────

SET client_encoding TO 'UTF8';

BEGIN;

-- 1. Refuse if chapter exists already.
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM chapters WHERE name = 'Protetica') THEN
    RAISE EXCEPTION 'Chapter "Protetica" already exists — refusing to re-import.';
  END IF;
END $$;

-- 2. Insert chapter (sort_order = max + 1) and capture its id.
VALUES ('Protetica', (SELECT COALESCE(MAX(sort_order), -1) + 1 FROM chapters))
RETURNING id AS chapter_id \gset

-- 3. Bulk-insert all 2444 questions with pre-generated UUIDs.

-- 4. Bulk-insert all 12220 options.

-- 5. Sanity check.
\echo ''
\echo '── Import summary ────────────────────────────────────────────────────────'
SELECT COUNT(*)::int AS inserted_questions FROM questions WHERE source_book = 'Protetica';
SELECT COUNT(*)::int AS inserted_options FROM options o JOIN questions q ON q.id = o.question_id WHERE q.source_book = 'Protetica';

COMMIT;